#include <stdio.h>
#include <stdlib.h>
#include <string.h>

long long powmod(long long a, long long b, long long m) {
    long long res = 1;
    while (b > 0) {
        if (b & 1)
            res = (res * a) % m;
        a = (a * a) % m;
        b >>= 1;
    }
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long M;
        char S[10005];
        scanf("%lld %s", &M, S);
        long long ans = 1;
        char *p = strtok(S, "*");
        while (p) {
            char *q = strtok(NULL, "**");
            long long a = atoi(p);
            long long b = atoi(q);
            ans = (ans * powmod(a, b, M)) % M;
            p = strtok(NULL, "*");
        }
        printf("%lld\n", ans);
    }
    return 0;
}

