import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long M = sc.nextLong();
            String S = sc.next();
            long ans = 1;
            String[] parts = S.split("*");
            for (String part : parts) {
                String[] subParts = part.split("**");
                long a = Long.parseLong(subParts[0]);
                long b = Long.parseLong(subParts[1]);
                ans = (ans * powmod(a, b, M)) % M;
            }
            System.out.println(ans);
        }
    }

    public static long powmod(long a, long b, long m) {
        long res = 1;
        while (b > 0) {
            if (b % 2 == 1)
                res = (res * a) % m;
            a = (a * a) % m;
            b >>= 1;
        }
        return res;
    }
}

